<script setup lang="ts">import { ElCheckbox,ElFormItem,ElInput,ElInputNumber } from 'element-plus';const model=defineModel<{allowedExtensions:string[];maxCount:number;maxSizeMb:number;required:boolean}>({required:true});</script>
<template><div class="grid"><ElFormItem label="最多附件数"><ElInputNumber v-model="model.maxCount" :min="0" :max="50"/></ElFormItem><ElFormItem label="单个文件上限（MB）"><ElInputNumber v-model="model.maxSizeMb" :min="1" :max="200"/></ElFormItem><ElFormItem label="允许的文件类型"><ElInput :model-value="model.allowedExtensions.join(', ')" placeholder="pdf, jpg, png" @update:model-value="value=>model.allowedExtensions=String(value).split(',').map(v=>v.trim().toLowerCase()).filter(Boolean)"/></ElFormItem></div><ElCheckbox v-model="model.required">必须上传附件</ElCheckbox></template><style scoped>.grid{display:grid;grid-template-columns:repeat(3,minmax(0,1fr));gap:0 16px}@media(max-width:760px){.grid{grid-template-columns:1fr}}</style>
